-- signals_hermes_runtime.db schema
-- Generated by git-master audit

CREATE TABLE signals (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    token TEXT NOT NULL,
    direction TEXT NOT NULL,
    signal_type TEXT NOT NULL,
    source TEXT,
    confidence REAL NOT NULL,
    value REAL,
    price REAL,
    exchange TEXT DEFAULT 'hyperliquid',
    timeframe TEXT DEFAULT '1h',
    decision TEXT DEFAULT 'PENDING',
    decision_reason TEXT,
    executed INTEGER DEFAULT 0,
    z_score REAL,
    z_score_tier TEXT,
    momentum_state TEXT,
    rsi_14 REAL,
    macd_value REAL,
    macd_signal REAL,
    macd_hist REAL,
    leverage INTEGER,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
, compact_rounds INTEGER DEFAULT 0, last_compact_at TEXT, survival_score REAL DEFAULT 0.0, learned_sl_multiplier REAL DEFAULT 1.0, review_count INTEGER DEFAULT 0);

CREATE TABLE momentum_cache (
    token TEXT PRIMARY KEY,
    phase TEXT,
    percentile_long REAL,
    percentile_short REAL,
    velocity REAL,
    avg_z REAL,
    z_direction TEXT,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
, momentum_state TEXT DEFAULT "neutral", state_confidence REAL DEFAULT 0.3);

CREATE TABLE token_intel (
    token TEXT PRIMARY KEY,
    exchange TEXT,
    max_leverage INTEGER,
    base_position_size REAL,
    open_positions INTEGER DEFAULT 0,
    last_signal_at TEXT,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE cooldown_tracker (
    token TEXT NOT NULL,
    direction TEXT NOT NULL,
    expires_at INTEGER NOT NULL,
    PRIMARY KEY(token, direction)
);

CREATE TABLE decisions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    token TEXT NOT NULL,
    direction TEXT NOT NULL,
    confidence REAL NOT NULL,
    entry_price REAL,
    exchange TEXT,
    decision TEXT NOT NULL,
    reason TEXT,
    server TEXT DEFAULT 'Hermes',
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

